#!/usr/bin/env node
// Extract the loaded memory image (per PT_LOAD segment) from an ELF binary and
// print it as a JSON object mapping virtual address -> 32-bit little-endian word.
'use strict';

const fs = require('fs');

const path = process.argv[2];
if (!path) {
  console.error('usage: node extract.js <elf-binary>');
  process.exit(1);
}

const buf = fs.readFileSync(path);

// --- ELF header sanity check ---
if (buf.length < 64 || buf.readUInt32LE(0) !== 0x464c457f) {
  console.error('not an ELF file');
  process.exit(1);
}
const eiClass = buf[4]; // 1 = 32-bit, 2 = 64-bit
if (eiClass !== 2) {
  console.error('only 64-bit ELF supported');
  process.exit(1);
}

const eType = buf.readUInt16LE(16);          // ET_EXEC=2, ET_DYN=3 (PIE)
const ePhoff = Number(buf.readBigUInt64LE(32));
const ePhentsize = buf.readUInt16LE(54);
const ePhnum = buf.readUInt16LE(56);

// A position-independent executable has virtual addresses starting at 0; the
// conventional load base for such an image is 0x400000. A non-PIE executable
// already carries absolute virtual addresses, so its base offset is 0.
const base = (eType === 3) ? 0x400000 : 0;

const PT_LOAD = 1;
const out = {};

for (let i = 0; i < ePhnum; i++) {
  const ph = ePhoff + i * ePhentsize;
  const pType = buf.readUInt32LE(ph);
  if (pType !== PT_LOAD) continue;

  const pOffset = Number(buf.readBigUInt64LE(ph + 8));
  const pVaddr = Number(buf.readBigUInt64LE(ph + 16));
  const pFilesz = Number(buf.readBigUInt64LE(ph + 32));

  // Emit every fully file-backed 4-byte word of this segment.
  const words = Math.floor(pFilesz / 4);
  for (let w = 0; w < words; w++) {
    const addr = base + pVaddr + w * 4;
    const val = buf.readUInt32LE(pOffset + w * 4);
    out[addr] = val;
  }
}

process.stdout.write(JSON.stringify(out));

