cd /app && node extract.js /app/a.out > out.json && node -e '
const fs=require("fs");
const txt=fs.readFileSync("/app/out.json","utf8");
const o=JSON.parse(txt);            // valid JSON
const buf=fs.readFileSync("/app/a.out");
// independent cross-check: verify every entry against a fresh vaddr->fileoffset map
// build PT_LOAD map
const phoff=Number(buf.readBigUInt64LE(32)), phes=buf.readUInt16LE(54), phn=buf.readUInt16LE(56);
const base=0x400000, segs=[];
for(let i=0;i<phn;i++){const ph=phoff+i*phes; if(buf.readUInt32LE(ph)!==1)continue;
  segs.push({off:Number(buf.readBigUInt64LE(ph+8)),va:Number(buf.readBigUInt64LE(ph+16)),fs:Number(buf.readBigUInt64LE(ph+32))});}
let bad=0, nonint=0;
for(const [k,v] of Object.entries(o)){
  if(!Number.isInteger(v)||v<0||v>0xffffffff)nonint++;
  const addr=Number(k)-base;
  const s=segs.find(s=>addr>=s.va&&addr+4<=s.va+s.fs);
  if(!s){bad++;continue;}
  const fileVal=buf.readUInt32LE(s.off+(addr-s.va));
  if(fileVal!==v)bad++;
}
console.log("entries",Object.keys(o).length,"mismatches",bad,"non-int",nonint);
console.log("JSON parse OK, all keys stringified, values numeric");
'

